{"content":"148:     @Override
149:     public void initChannel(
150:             Route route,
151:             NamedNode definition,
152:             NamedNode childDefinition,
153:             List<InterceptStrategy> interceptors,
154:             Processor nextProcessor,
155:             NamedRoute routeDefinition,
156:             boolean first)
157:             throws Exception {
158:         this.route = route;
159:         this.nextProcessor = nextProcessor;
160: 
161:         // init CamelContextAware as early as possible on nextProcessor
162:         CamelContextAware.trySetCamelContext(nextProcessor, camelContext);
163: 
164:         // the definition to wrap should be the fine grained,
165:         // so if a child is set then use it, if not then its the original output used
166:         NamedNode targetOutputDef = childDefinition != null ? childDefinition : definition;
167:         LOG.trace("Initialize channel for target: {}", targetOutputDef);
168: 
169:         // setup instrumentation processor for management (jmx)
170:         // this is later used in postInitChannel as we need to setup the error handler later as well
171:         ManagementInterceptStrategy managed = route.getManagementInterceptStrategy();
172:         if (managed != null) {
173:             instrumentationProcessor = managed.createProcessor(targetOutputDef, nextProcessor);
174:         }
175: 
176:         // then wrap the output with the tracer and debugger (debugger first,
177:         // as we do not want regular tracer to trace the debugger)
178:         if (camelContext.isDebugStandby() || route.isDebugging()) {
179:             final Debugger customDebugger = camelContext.getDebugger();
180:             final MessageHistoryFactory messageHistoryFactory = camelContext.getMessageHistoryFactory();
181:             if (customDebugger != null) {
182:                 // use custom debugger
183:                 addAdvice(new MessageHistoryAdvice(messageHistoryFactory, targetOutputDef));
184:                 addAdvice(new DebuggerAdvice(customDebugger, nextProcessor, targetOutputDef));
185:             }
186:             BacklogDebugger debugger = getBacklogDebugger(camelContext, customDebugger == null);
187:             if (debugger != null) {
188:                 // use backlog debugger
189:                 if (!camelContext.hasService(debugger)) {
190:                     camelContext.addService(debugger);
191:                 }
192:                 // skip debugging inside rest-dsl (just a tiny facade) or kamelets / route-templates
193:                 boolean skip = routeDefinition != null
194:                         && (routeDefinition.isCreatedFromRest() || routeDefinition.isCreatedFromTemplate());
195:                 if (!skip && routeDefinition != null) {
196:                     backlogDebuggerSetupInitialBreakpoints(definition, routeDefinition, first, debugger, targetOutputDef);
197:                     if (first && debugger.isSingleStepIncludeStartEnd()) {
198:                         // debugger captures message history, and we need to capture history of incoming
199:                         addAdvice(
200:                                 new MessageHistoryAdvice(camelContext.getMessageHistoryFactory(), routeDefinition.getInput()));
201:                         // add breakpoint on route input instead of first node
202:                         addAdvice(new BacklogDebuggerAdvice(debugger, nextProcessor, routeDefinition.getInput()));
203:                     }
204:                     addAdvice(new MessageHistoryAdvice(messageHistoryFactory, targetOutputDef));
205:                     addAdvice(new BacklogDebuggerAdvice(debugger, nextProcessor, targetOutputDef));
206:                 }
207:             }
208:         }
209: 
210:         if (camelContext.isBacklogTracingStandby() || route.isBacklogTracing()) {
211:             // add jmx backlog tracer
212:             BacklogTracer backlogTracer = getOrCreateBacklogTracer(camelContext);
213:             addAdvice(new BacklogTracerAdvice(camelContext, backlogTracer, targetOutputDef, routeDefinition));
214:         }
215:         if (route.isTracing() || camelContext.isTracingStandby()) {
216:             // add logger tracer
217:             Tracer tracer = camelContext.getTracer();
218:             addAdvice(new TracingAdvice(camelContext, tracer, targetOutputDef, routeDefinition, first));
219:         }
220: 
221:         // debugger will automatically include message history
222:         boolean debugging = camelContext.isDebugStandby() || route.isDebugging();
223:         if (!debugging && route.isMessageHistory()) {
224:             final MessageHistoryFactory messageHistoryFactory = camelContext.getMessageHistoryFactory();
225:             // add message history advice (when not debugging)
226:             addAdvice(new MessageHistoryAdvice(messageHistoryFactory, targetOutputDef));
227:         }
228:         // add advice that keeps track of which node is processing
229:         addAdvice(new NodeHistoryAdvice(targetOutputDef));
230: 
231:         // sort interceptors according to ordered
232:         interceptors.sort(OrderedComparator.get());
233:         // reverse list so the first will be wrapped last, as it would then be first being invoked
234:         Collections.reverse(interceptors);
235:         // wrap the output with the configured interceptors
236:         Processor target = nextProcessor;
237:         boolean skip = target instanceof InterceptableProcessor ip && !ip.canIntercept();
238:         if (!skip) {
239:             for (InterceptStrategy strategy : interceptors) {
240:                 Processor next = target == nextProcessor ? null : nextProcessor;
241:                 // use the fine grained definition (eg the child if available). Its always possible to get back to the parent
242:                 Processor wrapped
243:                         = strategy.wrapProcessorInInterceptors(route.getCamelContext(), targetOutputDef, target, next);
244:                 if (!(wrapped instanceof AsyncProcessor)) {
245:                     LOG.warn("Interceptor: {} at: {} does not return an AsyncProcessor instance."
246:                              + " This causes the asynchronous routing engine to not work as optimal as possible."
247:                              + " See more details at the InterceptStrategy javadoc."
248:                              + " Camel will use a bridge to adapt the interceptor to the asynchronous routing engine,"
249:                              + " but its not the most optimal solution. Please consider changing your interceptor to comply.",
250:                             strategy, definition);
251:                 }
252:                 if (!(wrapped instanceof WrapAwareProcessor)) {
253:                     // wrap the target so it becomes a service and we can manage its lifecycle
254:                     wrapped = PluginHelper.getInternalProcessorFactory(camelContext)
255:                             .createWrapProcessor(wrapped, target);
256:                 }
257:                 target = wrapped;
258:             }
259:         }
260: 
261:         if (route.isStreamCaching()) {
262:             addAdvice(new StreamCachingAdvice(camelContext.getStreamCachingStrategy()));
263:         }
264: 
265:         if (route.getDelayer() != null && route.getDelayer() > 0) {
266:             addAdvice(new DelayerAdvice(route.getDelayer()));
267:         }
268: 
269:         // sets the delegate to our wrapped output
270:         output = target;
271:     }
