351:     /**
352:      * Determines whether a new thread pool will be created or not.
353:      * <p/>
354:      * This is used to know if a new thread pool will be created, and therefore is not shared by others, and therefore
355:      * exclusive to the definition.
356:      *
357:      * @param  definition the node definition which may leverage executor service.
358:      * @param  useDefault whether to fallback and use a default thread pool, if no explicit configured
359:      * @return            <tt>true</tt> if a new thread pool will be created, <tt>false</tt> if not
360:      * @see               #getConfiguredExecutorService(String, ExecutorServiceAwareDefinition, boolean)
361:      */
362:     public boolean willCreateNewThreadPool(ExecutorServiceAwareDefinition<?> definition, boolean useDefault) {
363:         ExecutorServiceManager manager = camelContext.getExecutorServiceManager();
364:         ObjectHelper.notNull(manager, "ExecutorServiceManager", camelContext);
365: 
366:         if (definition.getExecutorServiceBean() != null) {
367:             // no there is a custom thread pool configured
368:             return false;
369:         } else if (definition.getExecutorServiceRef() != null) {
370:             ExecutorService answer = lookupByNameAndType(definition.getExecutorServiceRef(), ExecutorService.class);
371:             // if no existing thread pool, then we will have to create a new
372:             // thread pool
373:             return answer == null;
374:         } else if (useDefault) {
375:             return true;
376:         }
377: 
378:         return false;
379:     }
