381:     /**
382:      * Will look up and get the configured {@link ExecutorService} from the given definition.
383:      * <p/>
384:      * This method will look up for configured thread pool in the following order
385:      * <ul>
386:      * <li>from the definition if any explicit configured executor service.</li>
387:      * <li>from the {@link org.apache.camel.spi.Registry} if found</li>
388:      * <li>from the known list of {@link org.apache.camel.spi.ThreadPoolProfile ThreadPoolProfile(s)}.</li>
389:      * <li>if none found, then <tt>null</tt> is returned.</li>
390:      * </ul>
391:      * The various {@link ExecutorServiceAwareDefinition} should use this helper method to ensure they support
392:      * configured executor services in the same coherent way.
393:      *
394:      * @param  name                     name which is appended to the thread name, when the {@link ExecutorService} is
395:      *                                  created based on a {@link org.apache.camel.spi.ThreadPoolProfile}.
396:      * @param  definition               the node definition which may leverage executor service.
397:      * @param  useDefault               whether to fallback and use a default thread pool, if no explicit configured
398:      * @return                          the configured executor service, or <tt>null</tt> if none was configured.
399:      * @throws IllegalArgumentException is thrown if lookup of executor service in {@link org.apache.camel.spi.Registry}
400:      *                                  was not found
401:      */
402:     public ExecutorService getConfiguredExecutorService(
403:             String name, ExecutorServiceAwareDefinition<?> definition, boolean useDefault)
404:             throws IllegalArgumentException {
405:         ExecutorServiceManager manager = camelContext.getExecutorServiceManager();
406:         ObjectHelper.notNull(manager, "ExecutorServiceManager", camelContext);
407: 
408:         // prefer to use explicit configured executor on the definition
409:         String ref = parseString(definition.getExecutorServiceRef());
410:         if (definition.getExecutorServiceBean() != null) {
411:             return definition.getExecutorServiceBean();
412:         } else if (ref != null) {
413:             // lookup in registry first and use existing thread pool if exists
414:             ExecutorService answer = lookupExecutorServiceRef(name, definition, ref);
415:             if (answer == null) {
416:                 throw new IllegalArgumentException(
417:                         "ExecutorServiceRef " + definition.getExecutorServiceRef()
418:                                                    + " not found in registry (as an ExecutorService instance) or as a thread pool profile.");
419:             }
420:             return answer;
421:         } else if (useDefault) {
422:             return manager.newDefaultThreadPool(definition, name);
423:         }
424: 
425:         return null;
426:     }
