654:     protected Channel wrapChannel(Processor processor, ProcessorDefinition<?> child, Boolean inheritErrorHandler)
655:             throws Exception {
656:         // put a channel in between this and each output to control the route flow logic
657:         Channel channel = PluginHelper.getInternalProcessorFactory(camelContext)
658:                 .createChannel(camelContext);
659: 
660:         // add interceptor strategies to the channel must be in this order:
661:         // camel context, route context, local
662:         List<InterceptStrategy> interceptors = new ArrayList<>();
663:         interceptors.addAll(camelContext.getCamelContextExtension().getInterceptStrategies());
664:         interceptors.addAll(route.getInterceptStrategies());
665:         interceptors.addAll(definition.getInterceptStrategies());
666: 
667:         // force the creation of an id
668:         RouteDefinitionHelper.forceAssignIds(camelContext, definition);
669: 
670:         // fix parent/child relationship. This will be the case of the routes
671:         // has been
672:         // defined using XML DSL or end user may have manually assembled a route
673:         // from the model.
674:         // Background note: parent/child relationship is assembled on-the-fly
675:         // when using Java DSL (fluent builders)
676:         // where as when using XML DSL (JAXB) then it fixed after, but if people
677:         // are using custom interceptors
678:         // then we need to fix the parent/child relationship beforehand, and
679:         // thus we can do it here
680:         // ideally we need the design time route -> runtime route to be a
681:         // 2-phase pass (scheduled work for Camel 3.0)
682:         if (child != null && definition != child) {
683:             child.setParent(definition);
684:         }
685: 
686:         // set the child before init the channel
687:         RouteDefinition route = ProcessorDefinitionHelper.getRoute(definition);
688:         boolean first = false;
689:         if (route != null && !route.getOutputs().isEmpty()) {
690:             first = route.getOutputs().get(0) == definition;
691:         }
692:         // special for aggregate which output are regarded as a new first
693:         NamedNode targetOutputDef = child != null ? child : definition;
694:         if (!first && targetOutputDef.getParent() instanceof AggregateDefinition agg) {
695:             first = agg.getOutputs().get(0) == targetOutputDef;
696:         }
697:         // initialize the channel
698:         channel.initChannel(this.route, definition, child, interceptors, processor, route, first);
699: 
700:         // set the error handler, must be done after init as we can set the
701:         // error handler as first in the chain
702:         boolean wrap = ProcessorDefinitionHelper.shouldWrapInErrorHandler(camelContext, definition, child, inheritErrorHandler);
703:         if (wrap) {
704:             wrapChannelInErrorHandler(channel, inheritErrorHandler);
705:         }
706: 
707:         // do post init at the end
708:         channel.postInitChannel();
709:         LOG.trace("{} wrapped in Channel: {}", definition, channel);
710: 
711:         return channel;
712:     }
